import random
import math
import datetime

def tell_joke():
    jokes = [
        "Why do programmers prefer dark mode? Because light attracts bugs!",
        "Why did the Python programmer wear glasses? Because they couldn't C!",
        "What do you call a sleeping dinosaur? A dino-snore!"
    ]
    return random.choice(jokes)

def do_math(expression):
    try:
        result = eval(expression)
        return f"The answer is {result}"
    except:
        return "I couldn't calculate that."

def get_time():
    now = datetime.datetime.now()
    return f"It is {now.strftime('%H:%M')} right now."

name = input("Hi! What's your name? ")
print(f"Nice to meet you, {name}! I'm your Python assistant.")
print("Commands: joke, math, random, time, quit")

while True:
    command = input(f"\n{name}: ").lower()
    if command == "quit":
        print(f"Goodbye, {name}! Keep coding!")
        break
    elif command == "joke":
        print(tell_joke())
    elif command == "math":
        expr = input("Enter a math expression: ")
        print(do_math(expr))
    elif command == "random":
        print(f"Your lucky number is {random.randint(1, 100)}!")
    elif command == "time":
        print(get_time())
    else:
        print("I don't know that command yet. Try: joke, math, random, time, quit")
